  scheduleText(task){const interval=Math.max(1,Number(task.interval)||1),fixed=task.recurrence_mode==="fixed",frequency=task.frequency||"monthly",next=task.due_date?`\nFälligkeit: ${this.date(task.due_date)}`:"";if(!fixed){const singular={daily:"jeden Tag",weekly:"jede Woche",monthly:"jeden Monat",yearly:"jedes Jahr"}[frequency],plural={daily:"Tage",weekly:"Wochen",monthly:"Monate",yearly:"Jahre"}[frequency];return `${interval===1?`Findet ${singular}`:`Findet alle ${interval} ${plural}`} nach der Erledigung statt.${next}`;}if(frequency==="daily")return `${interval===1?"Findet jeden Tag statt.":`Findet alle ${interval} Tage statt.`}${next}`;if(frequency==="weekly"){const names=["Montag","Dienstag","Mittwoch","Donnerstag","Freitag","Samstag","Sonntag"],days=(task.weekdays||[]).map(day=>names[Number(day)]).filter(Boolean),when=days.length?` am ${days.join(", ").replace(/, ([^,]*)$/," und $1")}`:"";return `${interval===1?"Findet jede Woche":`Findet alle ${interval} Wochen`}${when} statt.${next}`;}const day=task.day_of_month==="last"?"am letzten Tag":`am ${Number(task.day_of_month)}.`;if(frequency==="yearly"){const month=new Intl.DateTimeFormat("de-CH",{month:"long"}).format(new Date(2024,Number(task.month_of_year||1)-1,1)),annualDay=task.day_of_month==="last"?`am letzten Tag im ${month}`:`am ${Number(task.day_of_month)}. ${month}`;return `${interval===1?"Findet jedes Jahr":`Findet alle ${interval} Jahre`} ${annualDay} statt.${next}`;}return `${interval===1?"Findet jeden Monat":`Findet alle ${interval} Monate`} ${day} statt.${next}`;}
  editorScheduleHtml(task,dueDates=[],status=""){const rule=esc(this.scheduleText(task).split("\n")[0]),rows=dueDates.map(due=>{const parts=this.dueDateParts(due);return `<div role="row" style="display:contents"><span role="cell">${esc(parts.weekday)}</span><span role="cell">${esc(parts.date)}</span></div>`;}).join("");return `<div>${rule}</div>${rows?`<div role="table" aria-label="Fälligkeiten" style="display:grid;grid-template-columns:max-content max-content;column-gap:12px;justify-content:start;margin-top:8px">${rows}</div>`:status?`<div style="margin-top:8px">${esc(status)}</div>`:""}`;}
  historyTime(entry){const value=entry.recorded_at?new Date(entry.recorded_at):null;return value&&!Number.isNaN(value.getTime())?value.toLocaleTimeString("de-CH",{hour:"2-digit",minute:"2-digit"}):"–";}
